# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor.{Actor, ActorLogging, ActorRef, Props}
import akka.actor.Status.Failure

case class Deposit(amount: Double, sender: ActorRef)
case class Withdrawal(amount: Double, sender: ActorRef)
case object AccountBalance

class AccountActor extends Actor {
  import AccountActor._
  var balance: Double = 0

  override def receive: Receive = initialReception

  def initialReception: Receive = {
    case AccountBalance => println(s"Initial Balance: $balance")
    case Deposit(amount, sender) =>
      balance += amount
      sender ! Success(s"Deposited $amount. New balance: $balance")
    case Withdrawal(amount, sender) if amount > balance =>
      sender ! Failure(new RuntimeException("Insufficient funds"))
    case Withdrawal(amount, sender) =>
      balance -= amount
      sender ! Success(s"Withdrew $amount. New balance: $balance")
  }
}

object AccountActor {
  def props: Props = Props[AccountActor]
}